using Microsoft.AspNetCore.Components.Authorization;
using sv_25c9d265b0c941e1893ff016e873fce7.Auth;
using sv_25c9d265b0c941e1893ff016e873fce7.Client.Pages;
using sv_25c9d265b0c941e1893ff016e873fce7.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<AuthenticationStateProvider, PersistingAuthenticationStateProvider>();
builder.Services.AddScoped<ServerAuthenticationStateProvider>();

// Wire up the server auth state into the persisting provider
builder.Services.AddScoped<IHostEnvironmentAuthenticationStateProvider>(sp =>
    (PersistingAuthenticationStateProvider)sp.GetRequiredService<AuthenticationStateProvider>());

builder.Services.AddAuthorization();

// Seed the persisting provider with the hardcoded auth state
builder.Services.AddScoped(sp =>
{
    var serverAuth = sp.GetRequiredService<ServerAuthenticationStateProvider>();
    var persistingAuth = (PersistingAuthenticationStateProvider)sp.GetRequiredService<AuthenticationStateProvider>();
    persistingAuth.SetAuthenticationState(serverAuth.GetAuthenticationStateAsync());
    return persistingAuth;
});

var app = builder.Build();

